const INSTANSI_MAP = { bapperida: 'BAPPERIDA Sumba Barat', dpmptsp: 'DPMPTSP Sumba Barat' };
const instansi_id = d.instansi_id || 'bapperida';
const instansi_name = INSTANSI_MAP[instansi_id] || instansi_id.toUpperCase();
const d = $('Auto Approve (S, T, TUBEL, CUTI)').first().json;
const jenis = d.row_jenis_base;
const em = { IZIN: '🙏', SAKIT: '🤒', TUGAS: '💼' }[jenis] || '📝';
const isApprove = d.action === 'APPROVE';
const icon = isApprove ? '✅' : '❌';
const label = isApprove ? 'DISETUJUI' : 'DITOLAK';
const text = `DIINFORMASIKAN BAHWA\n━━━━━━━━━━━━━━━━━━\n${icon} *STATUS: ${label}*\n${em} *${jenis}* — ${d.tgl_range}\n👤 *${d.row_nama}*\n📝 ${d.row_ket || '—'}\n━━━━━━━━━━━━━━━━━━\n_Pengumuman dari Admin ${instansi_name}_`;

const pegawai = $input.all().map(i => i.json).filter(p => {
  const id = String(p.id || '').trim();
  const st = String(p.Status || p.status || 'AKTIF').toUpperCase();
  return id && st !== 'NONAKTIF' && st !== 'INACTIVE';
});

return pegawai.map(p => ({ json: { chat_id: String(p.id), text } }));

const d = $input.first().json;

const dates = (d.dates && d.dates.length) ? d.dates : [d.row_tgl_mulai].filter(Boolean);
if (!dates.length) return [{json:{...d, tanggal_this:'', id_ket: (d.target_id_ket||'UNK') + '_01'}}];

const prefixMap = { IZIN:'IZN', SAKIT:'SKT', TUGAS:'TGS' };
const jenisBase = (d.row_jenis_base||'').toUpperCase();
const prefix = prefixMap[jenisBase] || jenisBase.slice(0,3);
const tglKey = (d.row_tgl_mulai||'').replace(/-/g,'');

const out = [];
dates.forEach((tgl, i) => {
  const suffix = String(i+1).padStart(2,'0');
  const tglSuffix = tgl.replace(/-/g, '');
  // 1. Catat Keterangan Utama (IZIN/SAKIT/TUGAS)
  out.push({
    json: {
      ...d,
      tanggal_this: tgl,
      id_ket: `${prefix}${tglKey}_${d.row_id}_${suffix}`,
      request_id: (d.request_id || '') + '_' + tglSuffix + suffix
    }
  });

  // 2. Jika IZIN dan Selesai >= 14:30, Otomatis Catat PULANG
  const jamSelesai = d.row_jam_selesai || '';
  if (jenisBase === 'IZIN' && jamSelesai >= '14:30') {
    out.push({
      json: {
        ...d,
        tanggal_this: tgl,
        row_jenis_base: 'PULANG',
        row_jam: jamSelesai,
        row_ket: `${d.row_ket} (Auto Pulang dari Izin Jam)`,
        id_ket: `PLG${tglKey}_${d.row_id}_${suffix}`,
        request_id: (d.request_id || '') + '_' + tglSuffix + suffix + '_PLG'
      }
    });
  }
});
return out;

const d = $input.first().json;
// ket_temp = 1 row per pengajuan, matching = [ID_Ket]
const rows = Array.isArray(d.matching_ket_rows) ? d.matching_ket_rows.flat().map(String).filter(Boolean) : [String(d.target_id_ket)];
return rows.map(idKet => ({ json: { ...d, target_id_ket: idKet } }));

const d=$input.first().json;
if(!d.ok) return [{json:d}];
const AUTO=['SAKIT','TUGAS','TUBEL','CUTI'];
if(AUTO.includes(d.row_jenis_base)) return [{json:{...d,action:'APPROVE',new_jenis_absen:d.row_jenis_base,_auto:true}}];
return [{json:d}];

const idKetRaw = $('Validasi Approve').item.json.id_ket;
const action   = $('Validasi Approve').item.json.action;
const jenis    = $('Validasi Approve').item.json.jenis;
const allRows  = $input.all();

// Normalisasi: strip suffix _01/_02 jika ada (ket_temp simpan tanpa suffix)
const idKet = String(idKetRaw).replace(/_\d{2}$/, '');

const match = allRows.find(r => String(r.json.ID_Ket||'').trim() === idKet.trim());
if (!match) return [{json:{ok:false, message:'Data tidak ditemukan di ket_temp.'}}];

const r = match.json;

const tglMulai   = r.tgl_mulai || '';
const tglSelesai = r.tgl_selesai || tglMulai;
const tglRange   = r.tanggal || (tglMulai === tglSelesai ? tglMulai : `${tglMulai} s.d. ${tglSelesai}`);

// Generate dates dari tgl_mulai sampai tgl_selesai
const dates = [];
if (tglMulai) {
  const start = new Date(tglMulai), end = new Date(tglSelesai||tglMulai);
  for (let d = new Date(start); d <= end; d.setDate(d.getDate()+1))
    dates.push(d.toISOString().split('T')[0]);
}
if (!dates.length) dates.push(tglMulai);

const nowStr = new Date().toLocaleString('en-US', {timeZone:'Asia/Makassar', hour12:false});
const now    = new Date(nowStr);
const tsStr  = `${now.getFullYear()}-${String(now.getMonth()+1).padStart(2,'0')}-${String(now.getDate()).padStart(2,'0')} ${String(now.getHours()).padStart(2,'0')}:${String(now.getMinutes()).padStart(2,'0')}`;

const newStatus     = action === 'APPROVE' ? 'DISETUJUI' : 'DITOLAK';
const newJenisAbsen = action === 'APPROVE' ? jenis : jenis + ' DITOLAK';

return [{json:{
  ok:                true,
  target_id_ket:     idKet,
  matching_ket_rows: [idKet],
  dates,
  tgl_range:         tglRange,
  new_status:        newStatus,
  new_jenis_absen:   newJenisAbsen,
  action,
  row_id:            String(r.ID_Pegawai || r.telegram_id || ''),
  row_nama:          r.Nama || r.nama || '',
  row_nip:           r.NIP  || r.nip  || '',
  row_tgl_mulai:     tglMulai,
  row_tgl_selesai:   tglSelesai,
  row_jam:           r.Jam || r.diajukan_at || tsStr.split(' ')[1],
  row_ket:           r.Ket || r.keterangan || '',
  row_jenis_base:    jenis,
  request_id:        r.request_id || '',
  timestamp:         tsStr
}}];

