const VALID_JENIS = ['IZIN', 'SAKIT', 'TUGAS'];

const rows = $input.all()
  .map(i => {
    const r = i.json;

    // Normalisasi field — handle schema baru (Supabase) dan lama (GSheets)
    const id_ket     = r.ID_Ket      || r.id_ket     || '';
    const user_id    = String(r.telegram_id || r.ID_Pegawai || r.ID || r.id || '').trim();
    const nama       = r.nama        || r.Nama        || '';
    const nip        = r.nip         || r.NIP         || '';
    const tanggal    = r.tanggal     || r.Tanggal     || '';
    const jam        = r.diajukan_at || r.Jam         || '';
    const jenis_raw  = String(r.jenis || r['Jenis Absen'] || r.jenis_absen || '').trim().toUpperCase();
    const keterangan = r.keterangan  || r.Ket         || '';
    const status     = String(r.status || r.Status    || '').trim();

    // Buang row yang tidak punya user_id atau jenis valid
    if (!user_id || !jenis_raw) return null;

    // Normalisasi jenis: hapus suffix status (PENDING, DITOLAK, DISETUJUI)
    const jenis_base = jenis_raw
      .replace(' PENDING','').replace(' DITOLAK','')
      .replace(' TOLAK','').replace(' DISETUJUI','').trim();
    if (!VALID_JENIS.includes(jenis_base)) return null;

    return {
      id_ket,
      user_id,
      nama,
      nip,
      tanggal,
      jam,
      jenis: jenis_base,
      keterangan,
      status,
    };
  })
  .filter(Boolean);

return [{ json: { ok: true, data: rows, count: rows.length } }];

